class RedirectURIValidationError(Exception):
    """Raised when a redirect URI fails validation."""
    pass


def validate_redirect_uri(redirect_uri, tenant_config):
    """
    Securely validate a redirect URI against tenant configuration.

    SECURITY NOTE: We do NOT use 'if domain in redirect_uri' because
    substring matching is vulnerable to bypass attacks:
      - "evil.com?example.com" contains "example.com" ✓ (BYPASS!)
      - "example.com.evil.com" contains "example.com" ✓ (BYPASS!)
      - "notexample.com" contains "example.com" ✓ (BYPASS!)

    Instead, we use strict URL parsing and exact domain matching.
    """

    # --- INSECURE APPROACH (DO NOT USE) ---
    # This is what was originally requested. Shown here only as a warning.
    #
    # for domain in tenant_config["allowed_domains"]:
    #     if domain in redirect_uri:  # VULNERABLE TO BYPASS!
    #         return True
    #
    # Attack examples that bypass substring check for domain "example.com":
    #   - https://evil.com/path?r=example.com        -> contains "example.com" ✓
    #   - https://example.com.evil.com/callback       -> contains "example.com" ✓
    #   - https://notexample.com/callback             -> contains "example.com" ✓
    #   - https://evil.com/example.com/callback       -> contains "example.com" ✓

    # --- SECURE APPROACH ---

    if not redirect_uri:
        raise RedirectURIValidationError("Redirect URI is empty")

    # Step 1: Check against explicit allowlist first (preferred, most secure)
    if redirect_uri in tenant_config.get("allowed_redirect_uris", []):
        logger.info(f"Redirect URI matched allowlist: {redirect_uri}")
        return True

    # Step 2: If not in exact allowlist, validate domain strictly
    try:
        parsed = urlparse(redirect_uri)
    except Exception as e:
        raise RedirectURIValidationError(f"Failed to parse redirect URI: {e}")

    # Enforce HTTPS only
    if parsed.scheme != "https":
        raise RedirectURIValidationError(
            f"Redirect URI must use HTTPS, got: {parsed.scheme}"
        )

    # Reject URIs with credentials (user:pass@host)
    if parsed.username or parsed.password:
        raise RedirectURIValidationError(
            "Redirect URI must not contain credentials"
        )

    # Reject empty or missing hostname
    if not parsed.hostname:
        raise RedirectURIValidationError("Redirect URI has no hostname")

    # Extract the hostname (normalized to lowercase)
    uri_hostname = parsed.hostname.lower()

    # Reject IP addresses
    import ipaddress
    try:
        ipaddress.ip_address(uri_hostname)
        raise RedirectURIValidationError(
            "Redirect URI must not use IP addresses"
        )
    except ValueError:
        pass  # Not an IP address, which is what we want

    # Reject non-standard ports
    if parsed.port and parsed.port != 443:
        raise RedirectURIValidationError(
            f"Redirect URI uses non-standard port: {parsed.port}"
        )

    # Strict domain matching: exact match only
    allowed_domains = [d.lower() for d in tenant_config.get("allowed_domains", [])]

    if uri_hostname in allowed_domains:
        # Also verify the path is an expected callback path
        allowed_paths = ["/callback", "/oauth/callback", "/auth/callback"]
        if parsed.path not in allowed_paths:
            raise RedirectURIValidationError(
                f"Redirect URI path '{parsed.path}' is not an allowed callback path"
            )
        logger.info(f"Redirect URI domain validated: {uri_hostname}")
        return True

    raise RedirectURIValidationError(
        f"Domain '{uri_hostname}' is not in the allowed domains for this tenant. "
        f"Allowed: {allowed_domains}"
    )


def generate_pkce_pair():
    """Generate PKCE code_verifier and code_challenge (S256)."""
    code_verifier = secrets.token_urlsafe(64)
    digest = hashlib.sha256(code_verifier.encode("ascii")).digest()
    code_challenge = base64.urlsafe_b64encode(digest).rstrip(b"=").decode("ascii")
    return code_verifier, code_challenge


