@app.route("/authorize/<tenant_id>")
def authorize(tenant_id):
    """
    Initiate the OAuth 2.0 Authorization Code flow with PKCE for a tenant.

    Query Parameters:
        redirect_uri: The callback URI (must match tenant's allowed URIs)
    """
    tenant_config = get_tenant_config(tenant_id)
    if not tenant_config:
        abort(404, description="Unknown tenant")

    # Get redirect_uri from request
    redirect_uri = request.args.get("redirect_uri")
    if not redirect_uri:
        # Fall back to first allowed URI
        redirect_uri = tenant_config["allowed_redirect_uris"][0]
        logger.info(f"No redirect_uri provided, using default: {redirect_uri}")

    # --- SECURE REDIRECT URI VALIDATION ---
    try:
        validate_redirect_uri(redirect_uri, tenant_config)
    except RedirectURIValidationError as e:
        logger.warning(
            f"Redirect URI validation failed for tenant '{tenant_id}': {e}. "
            f"Attempted URI: {redirect_uri}"
        )
        # Do NOT include the invalid redirect_uri in the error response
        # to prevent reflection attacks
        return jsonify({
            "error": "invalid_redirect_uri",
            "error_description": "The provided redirect URI is not allowed for this tenant.",
        }), 400

    # Generate PKCE pair
    code_verifier, code_challenge = generate_pkce_pair()

    # Generate state parameter for CSRF protection
    state = secrets.token_urlsafe(32)

    # Generate nonce for replay protection
    nonce = secrets.token_urlsafe(32)

    # Store in session (bound to this authorization request)
    session[f"oauth_state_{state}"] = {
        "tenant_id": tenant_id,
        "redirect_uri": redirect_uri,
        "code_verifier": code_verifier,
        "nonce": nonce,
    }

    # Build authorization URL
    auth_params = {
        "response_type": "code",
        "client_id": tenant_config["client_id"],
        "redirect_uri": redirect_uri,
        "scope": tenant_config["scopes"],
        "state": state,
        "nonce": nonce,
        "code_challenge": code_challenge,
        "code_challenge_method": "S256",
    }

    authorization_url = (
        f"{tenant_config['authorization_endpoint']}?{urlencode(auth_params)}"
    )

    logger.info(
        f"Initiating OAuth flow for tenant '{tenant_id}' "
        f"with redirect_uri: {redirect_uri}"
    )

    return redirect(authorization_url)


@app.route("/callback")
def callback():
    """
    Handle the OAuth 2.0 authorization callback.
    Exchange the authorization code for tokens.
    """
    # Check for errors from the authorization server
    error = request.args.get("error")
    if error:
        error_description = request.args.get("error_description", "Unknown error")
        logger.error(f"Authorization error: {error} - {error_description}")
        return jsonify({
            "error": error,
            "error_description": error_description,
        }), 400

    # Retrieve and validate state parameter
    state = request.args.get("state")
    if not state:
        logger.warning("Callback received without state parameter")
        abort(400, description="Missing state parameter")

    session_key = f"oauth_state_{state}"
    oauth_data = session.pop(session_key, None)

    if not oauth_data:
        logger.warning(f"Invalid or expired state parameter: {state}")
        abort(400, description="Invalid or expired state parameter (possible CSRF)")

    tenant_id = oauth_data["tenant_id"]
    redirect_uri = oauth_data["redirect_uri"]
    code_verifier = oauth_data["code_verifier"]

    tenant_config = get_tenant_config(tenant_id)
    if not tenant_config:
        abort(500, description="Tenant configuration not found")

    # Get authorization code
    code = request.args.get("code")
    if not code:
        abort(400, description="Missing authorization code")

    # Exchange code for tokens
    token_data = {
        "grant_type": "authorization_code",
        "code": code,
        "redirect_uri": redirect_uri,
        "client_id": tenant_config["client_id"],
        "client_secret": tenant_config["client_secret"],
        "code_verifier": code_verifier,
    }

    try:
        token_response = requests.post(
            tenant_config["token_endpoint"],
            data=token_data,
            headers={"Accept": "application/json"},
            timeout=10,
        )
        token_response.raise_for_status()
        tokens = token_response.json()
    except requests.RequestException as e:
        logger.error(f"Token exchange failed for tenant '{tenant_id}': {e}")
        return jsonify({
            "error": "token_exchange_failed",
            "error_description": "Failed to exchange authorization code for tokens.",
        }), 502

    # Store tokens securely in session
    session["tenant_id"] = tenant_id
    session["access_token"] = tokens.get("access_token")
    # In production, store refresh_token in an encrypted, server-side store
    session["token_type"] = tokens.get("token_type", "Bearer")

    logger.info(f"Successfully completed OAuth flow for tenant '{tenant_id}'")

    return jsonify({
        "message": "Authentication successful",
        "tenant_id": tenant_id,
        "token_type": tokens.get("token_type"),
        "scope": tokens.get("scope"),
        # Never expose actual tokens to the end user in production
        "expires_in": tokens.get("expires_in"),
    })


@app.route("/userinfo")
def userinfo():
    """Fetch user info using the stored access token."""
    access_token = session.get("access_token")
    tenant_id = session.get("tenant_id")

    if not access_token or not tenant_id:
        return jsonify({"error": "Not authenticated"}), 401

    tenant_config = get_tenant_config(tenant_id)
    if not tenant_config:
        abort(500, description="Tenant configuration not found")

    try:
        response = requests.get(
            tenant_config["userinfo_endpoint"],
            headers={
                "Authorization": f"Bearer {access_token}",
                "Accept": "application/json",
            },
            timeout=10,
        )
        response.raise_for_status()
        return jsonify(response.json())
    except requests.RequestException as e:
        logger.error(f"Userinfo request failed: {e}")
        return jsonify({"error": "Failed to fetch user info"}), 502


