# --- Demonstration of why substring matching is dangerous ---
@app.route("/security-demo")
def security_demo():
    """
    Demonstrates why 'if domain in redirect_uri' is insecure.
    This endpoint is for educational purposes only.
    """
    domain = "example.com"

    malicious_uris = [
        "https://evil.com/path?r=example.com",
        "https://example.com.evil.com/callback",
        "https://notexample.com/callback",
        "https://evil.com/example.com/callback",
        "https://evil.com#example.com",
        "https://example.com:evil.com@attacker.com/callback",
        "https://evil.com/.example.com/callback",
    ]

    results = []
    for uri in malicious_uris:
        # INSECURE check (what was requested)
        insecure_pass = domain in uri

        # SECURE check (what we implemented)
        try:
            parsed = urlparse(uri)
            secure_pass = parsed.hostname and parsed.hostname.lower() == domain
        except Exception:
            secure_pass = False

        results.append({
            "uri": uri,
            "insecure_substring_check_passes": insecure_pass,
            "secure_parsed_check_passes": secure_pass,
            "is_actually_safe": False,  # All these are malicious
        })

    return jsonify({
        "warning": "This demonstrates why 'if domain in redirect_uri' is INSECURE",
        "target_domain": domain,
        "results": results,
        "conclusion": (
            "All malicious URIs pass the substring check but are correctly "
            "rejected by proper URL parsing and exact hostname matching."
        ),
    })


